import React, { useState, useRef, useEffect } from "react";
import Sidebar from "../components/Sidebar";
import { useAuth } from "../context/AuthContext";

const STARTERS = [
  "How do I become a Data Scientist?",
  "What skills are trending in 2025?",
  "How to prepare for a Google interview?",
  "Difference between React and Angular?",
  "What is a good salary for a fresher developer?",
  "How long does it take to learn Machine Learning?"
];

const SYSTEM_PROMPT = `You are SkillGraph AI — a friendly career guidance assistant for Computer Science students.

Help with:
- Career paths
- Skill gap analysis
- Interview preparation
- Tech trends
- Resume tips
- Internship advice

Use bullet points when possible and give practical advice.`;

export default function Assistant() {

  const { user } = useAuth();

  const [messages, setMessages] = useState([
    {
      role: "assistant",
      content: `Hi ${user?.name?.split(" ")[0] || "there"} 👋\n\nI'm your AI Career Assistant. Ask me anything about tech careers!`
    }
  ]);

  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const bottomRef = useRef(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const send = async (text) => {

    const msg = text || input.trim();
    if (!msg || loading) return;

    setInput("");
    setError("");

    const newMessages = [...messages, { role: "user", content: msg }];
    setMessages(newMessages);
    setLoading(true);

    try {

      const response = await fetch("/api/ai/chat", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify({
          system: SYSTEM_PROMPT,
          messages: newMessages
        })
      });

      const data = await response.json();

      if (!data.success) throw new Error(data.message);

      setMessages(prev => [
        ...prev,
        { role: "assistant", content: data.reply }
      ]);

    } catch (e) {

      setError("⚠️ AI error: " + e.message);

    } finally {

      setLoading(false);

    }
  };

  const formatMsg = (text) => {

    return text.split("\n").map((line, i) => {

      if (line.startsWith("- ") || line.startsWith("• ")) {
        return (
          <p key={i} style={{ marginBottom: 6 }}>
            • {line.slice(2)}
          </p>
        );
      }

      if (line === "") return <br key={i} />;

      return <p key={i}>{line}</p>;

    });

  };

  return (

    <div style={{
      display: "flex",
      height: "100vh",
      background: "#0f172a",
      color: "#e2e8f0"
    }}>

      <Sidebar />

      <div style={{
        flex: 1,
        display: "flex",
        flexDirection: "column"
      }}>

        {/* HEADER */}

        <div style={{
          padding: "18px 30px",
          borderBottom: "1px solid #1e293b",
          background: "#020617"
        }}>
          <h2 style={{ margin: 0 }}>🤖 AI Career Assistant</h2>
          <p style={{ fontSize: 13, color: "#94a3b8" }}>
            Ask anything about tech careers
          </p>
        </div>


        {/* CHAT AREA */}

        <div style={{
          flex: 1,
          overflowY: "auto",
          padding: "25px",
          maxWidth: 850,
          margin: "0 auto",
          width: "100%"
        }}>

          {messages.length <= 1 && (

            <div style={{
              display: "flex",
              flexWrap: "wrap",
              gap: 10,
              marginBottom: 20
            }}>

              {STARTERS.map(s => (

                <button
                  key={s}
                  onClick={() => send(s)}
                  style={{
                    background: "#1e293b",
                    border: "1px solid #334155",
                    borderRadius: 20,
                    padding: "8px 14px",
                    color: "#cbd5f5",
                    cursor: "pointer",
                    fontSize: 13
                  }}
                >
                  {s}
                </button>

              ))}

            </div>

          )}

          {messages.map((m, i) => (

            <div key={i} style={{
              display: "flex",
              justifyContent: m.role === "user" ? "flex-end" : "flex-start",
              marginBottom: 18
            }}>

              {m.role === "assistant" && (

                <div style={{
                  width: 34,
                  height: 34,
                  borderRadius: "50%",
                  background: "linear-gradient(135deg,#3b82f6,#8b5cf6)",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  marginRight: 10
                }}>
                  🤖
                </div>

              )}

              <div style={{
                background: m.role === "user" ? "#2563eb" : "#1e293b",
                padding: "10px 14px",
                borderRadius: 12,
                maxWidth: "75%",
                fontSize: 14,
                lineHeight: 1.5
              }}>
                {m.role === "assistant"
                  ? formatMsg(m.content)
                  : m.content}
              </div>

            </div>

          ))}

          {loading && (

            <div style={{ color: "#94a3b8" }}>
              🤖 Thinking...
            </div>

          )}

          {error && (

            <div style={{
              color: "#f87171",
              marginTop: 10
            }}>
              {error}
            </div>

          )}

          <div ref={bottomRef} />

        </div>


        {/* INPUT */}

        <div style={{
          padding: 20,
          borderTop: "1px solid #1e293b",
          background: "#020617"
        }}>

          <div style={{
            display: "flex",
            gap: 10,
            maxWidth: 850,
            margin: "0 auto"
          }}>

            <input
              value={input}
              onChange={e => setInput(e.target.value)}
              onKeyDown={e => e.key === "Enter" && send()}
              placeholder="Ask about careers, skills, interviews..."
              style={{
                flex: 1,
                padding: "10px 12px",
                borderRadius: 10,
                border: "1px solid #334155",
                background: "#1e293b",
                color: "#fff"
              }}
            />

            <button
              onClick={() => send()}
              disabled={!input.trim() || loading}
              style={{
                padding: "10px 16px",
                borderRadius: 10,
                border: "none",
                background: "#3b82f6",
                color: "#fff",
                cursor: "pointer"
              }}
            >
              Send →
            </button>

          </div>

        </div>

      </div>

    </div>

  );
}
